mapper.select:
SELECT DISTINCT n.id, n.title, n.summary, n.category_id, c.name AS category_name, n.created_at, n.updated_at FROM note n LEFT JOIN category c ON n.category_id = c.id
INNER JOIN note_tag nt ON n.id = nt.note_id AND nt.tag_id = #{tagId}
n.category_id = #{categoryId}
ORDER BY
n.created_at n.title n.updated_at
ASC DESC
